/**
 * Aperiodic Scheduling (Resonance-Free Scheduling)
 *
 * Periodic scheduling (round-robin) creates resonance: when multiple periodic 
 * schedulers share infrastructure, their coincident phase-lock concentrates load 
 * at common multiples -- thundering herds. 
 * 
 * To prevent eddies, the Syzygy Cannon rotates inference lanes by φ⁻¹ fractions 
 * per batch, guaranteeing that no two consecutive batches hit the same cache pattern.
 *
 * @module @a0n/gnosis/aperiodic-scheduling
 */

import { PHI_INV } from './holy-trinity';
import { type FlowObstruction, eddyCurrent } from './flow-obstruction';

/**
 * Calculates the next aperiodic cursor position given the current cursor.
 * Moves the cursor forward by φ⁻¹ * width to prevent phase-lock and resonant eddies.
 * 
 * @param currentCursor The current raw (float) cursor position
 * @param width The number of lanes/paths
 * @returns The next cursor position
 */
export function advanceAperiodicCursor(currentCursor: number, width: number): number {
  try {
    if (width <= 0) return 0;
    return (currentCursor + PHI_INV * width) % width;

  } catch (error) {
    throw new Error(`[advanceAperiodicCursor] ${error instanceof Error ? error.message : String(error)}`);
  }
}

/**
 * Gets the concrete lane index from a raw aperiodic cursor.
 * 
 * @param cursor The raw (float) cursor
 * @param width The number of lanes/paths
 * @returns The integer lane index
 */
export function getAperiodicLaneIndex(cursor: number, width: number): number {
  try {
    if (width <= 0) return 0;
    return Math.floor(cursor) % width;

  } catch (error) {
    throw new Error(`[getAperiodicLaneIndex] ${error instanceof Error ? error.message : String(error)}`);
  }
}

/**
 * Analyzes whether a scheduling configuration forms an eddy current obstruction.
 * Periodic (integer) strides across a manifold generate recirculating eddies.
 * 
 * @param stride The offset added to the cursor each tick
 * @param width The number of lanes
 * @returns A flow obstruction if an eddy forms, null otherwise
 */
export function analyzeEddyFormation(stride: number, width: number): FlowObstruction | null {
  try {
    if (width <= 1) return null;
  
    // Integer strides exactly phase-lock and recirculate
    if (Number.isInteger(stride)) {
      return eddyCurrent(1, width - 1);
    }
  
    return null;

  } catch (error) {
    throw new Error(`[analyzeEddyFormation] ${error instanceof Error ? error.message : String(error)}`);
  }
}
